TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- En el caso de INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_SERVICIOS_DE_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_SERVICIOS_DE_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_SERVICIOS_DE_ENTIDAD ( ENVIO_BQ, ID, ID_ENTIDAD, NUMERO_SERVICIO_ENTIDAD, CODIGO_PACIENTE_ENTIDAD, NOMBRE_PACIENTE_ENTIDAD, ID_SERVICIO, NOMBRE_SERVICIO_ENTIDAD, CANTIDAD_ASIGNADA, CANTIDAD_UTILIZADA, ESTADO_SERVICIO_ENTIDAD, FECHA_CREACION, AUTORIZACION_COOMEVA, VALOR_COPAGO, FECHA_AUTORIZACION_COOMEVA, ID_CITA, CODIGO_HISTORIA ) VALUES ( 0, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_ENTIDAD, :NEW.NUMERO_SERVICIO_ENTIDAD, :NEW.CODIGO_PACIENTE_ENTIDAD, :NEW.NOMBRE_PACIENTE_ENTIDAD, :NEW.ID_SERVICIO, :NEW.NOMBRE_SERVICIO_ENTIDAD, :NEW.CANTIDAD_ASIGNADA, :NEW.CANTIDAD_UTILIZADA, :NEW.ESTADO_SERVICIO_ENTIDAD, :NEW.FECHA_CREACION, :NEW.AUTORIZACION_COOMEVA, :NEW.VALOR_COPAGO, :NEW.FECHA_AUTORIZACION_COOMEVA, :NEW.ID_CITA, :NEW.CODIGO_HISTORIA ); END IF;
-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_SERVICIOS_DE_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_SERVICIOS_DE_ENTIDAD ( ENVIO_BQ, ID, ID_ENTIDAD, NUMERO_SERVICIO_ENTIDAD, CODIGO_PACIENTE_ENTIDAD, NOMBRE_PACIENTE_ENTIDAD, ID_SERVICIO, NOMBRE_SERVICIO_ENTIDAD, CANTIDAD_ASIGNADA, CANTIDAD_UTILIZADA, ESTADO_SERVICIO_ENTIDAD, FECHA_CREACION, AUTORIZACION_COOMEVA, VALOR_COPAGO, FECHA_AUTORIZACION_COOMEVA, ID_CITA, CODIGO_HISTORIA ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_ENTIDAD, :NEW.NUMERO_SERVICIO_ENTIDAD, :NEW.CODIGO_PACIENTE_ENTIDAD, :NEW.NOMBRE_PACIENTE_ENTIDAD, :NEW.ID_SERVICIO, :NEW.NOMBRE_SERVICIO_ENTIDAD, :NEW.CANTIDAD_ASIGNADA, :NEW.CANTIDAD_UTILIZADA, :NEW.ESTADO_SERVICIO_ENTIDAD, :NEW.FECHA_CREACION, :NEW.AUTORIZACION_COOMEVA, :NEW.VALOR_COPAGO, :NEW.FECHA_AUTORIZACION_COOMEVA, :NEW.ID_CITA, :NEW.CODIGO_HISTORIA );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_SERVICIOS_DE_ENTIDAD SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, ID_ENTIDAD = :NEW.ID_ENTIDAD, NUMERO_SERVICIO_ENTIDAD = :NEW.NUMERO_SERVICIO_ENTIDAD, CODIGO_PACIENTE_ENTIDAD = :NEW.CODIGO_PACIENTE_ENTIDAD, NOMBRE_PACIENTE_ENTIDAD = :NEW.NOMBRE_PACIENTE_ENTIDAD, ID_SERVICIO = :NEW.ID_SERVICIO, NOMBRE_SERVICIO_ENTIDAD = :NEW.NOMBRE_SERVICIO_ENTIDAD, CANTIDAD_ASIGNADA = :NEW.CANTIDAD_ASIGNADA, CANTIDAD_UTILIZADA = :NEW.CANTIDAD_UTILIZADA, ESTADO_SERVICIO_ENTIDAD = :NEW.ESTADO_SERVICIO_ENTIDAD, FECHA_CREACION = :NEW.FECHA_CREACION, AUTORIZACION_COOMEVA = :NEW.AUTORIZACION_COOMEVA, VALOR_COPAGO = :NEW.VALOR_COPAGO, FECHA_AUTORIZACION_COOMEVA = :NEW.FECHA_AUTORIZACION_COOMEVA, ID_CITA = :NEW.ID_CITA, CODIGO_HISTORIA = :NEW.CODIGO_HISTORIA WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_SERVICIOS_DE_ENTIDAD WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_SERVICIOS_DE_ENTIDAD WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_SERVICIOS_DE_ENTIDAD ( ENVIO_BQ, ID, ID_ENTIDAD, NUMERO_SERVICIO_ENTIDAD, CODIGO_PACIENTE_ENTIDAD, NOMBRE_PACIENTE_ENTIDAD, ID_SERVICIO, NOMBRE_SERVICIO_ENTIDAD, CANTIDAD_ASIGNADA, CANTIDAD_UTILIZADA, ESTADO_SERVICIO_ENTIDAD, FECHA_CREACION, AUTORIZACION_COOMEVA, VALOR_COPAGO, FECHA_AUTORIZACION_COOMEVA, ID_CITA, CODIGO_HISTORIA ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.ID_ENTIDAD, :OLD.NUMERO_SERVICIO_ENTIDAD, :OLD.CODIGO_PACIENTE_ENTIDAD, :OLD.NOMBRE_PACIENTE_ENTIDAD, :OLD.ID_SERVICIO, :OLD.NOMBRE_SERVICIO_ENTIDAD, :OLD.CANTIDAD_ASIGNADA, :OLD.CANTIDAD_UTILIZADA, :OLD.ESTADO_SERVICIO_ENTIDAD, :OLD.FECHA_CREACION, :OLD.AUTORIZACION_COOMEVA, :OLD.VALOR_COPAGO, :OLD.FECHA_AUTORIZACION_COOMEVA, :OLD.ID_CITA, :OLD.CODIGO_HISTORIA ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_SERVICIOS_DE_ENTIDAD'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
